import{_ as t,c as o,o as n,ai as r}from"./chunks/framework.DAgOazla.js";const h=JSON.parse('{"title":"Summit on European Digital Sovereignty Side Event","description":"","frontmatter":{"title":"Summit on European Digital Sovereignty Side Event","date":"2025-11-18","banner":"assets/events/20251118_summit_on_european_digital_sovereignty_neonephos_side_event_banner.jpg","bannerMobile":"assets/events/20251118_summit_on_european_digital_sovereignty_neonephos_side_eventbanner_mobile.jpg","backgroundhex":"#881aa4ff","tags":["neonephos","digital sovereignty","eu"],"published":true,"sidebar":false,"aside":false,"prev":false,"next":false,"layout":"EventEntryThemeComponent"},"headers":[],"relativePath":"events/2025_11_18_Summit_On_European_Digital_Sovereignty_NeoNephos_Side_Event.md","filePath":"events/2025_11_18_Summit_On_European_Digital_Sovereignty_NeoNephos_Side_Event.md"}'),i={name:"events/2025_11_18_Summit_On_European_Digital_Sovereignty_NeoNephos_Side_Event.md"};function a(s,e,u,p,d,_){return n(),o("div",null,e[0]||(e[0]=[r('<h1 id="neonephos-at-the-summit-on-european-digital-sovereignty" tabindex="-1">NeoNephos at the Summit on European Digital Sovereignty <a class="header-anchor" href="#neonephos-at-the-summit-on-european-digital-sovereignty" aria-label="Permalink to &quot;NeoNephos at the Summit on European Digital Sovereignty&quot;">​</a></h1><p>Learn more about NeoNephos at the upcoming <em>Role of Open Source to advance the Sovereign Cloud Edge Continuum</em> side event of the <a href="https://bmds.bund.de/aktuelles/eu-summit/side-events-overview" target="_blank" rel="noreferrer">Summit on European Digital Sovereignty</a>.</p><p>Within this event, representatives from our members introduce the audience through interactive talks to our projects and the value our foundation provides to the sovereign cloud native ecosystem.</p><hr><p><strong>Headline</strong>: <a href="https://bmds.bund.de/aktuelles/eu-summit/side-events-overview" target="_blank" rel="noreferrer">Role of Open Source to advance the Sovereign Cloud Edge Continuum</a></p><p><strong>Full Invitation Text</strong>:</p><p><em>The 8ra Initiative is driving the development of a sovereign, interoperable, and secure Multi-Provider Cloud-Edge Continuum. With more than 120 partners from 12 EU Member States, the 8ra Initiative fosters open collaboration to create a resilient and scalable digital infrastructure tailored to Europe’s needs. By promoting open-source innovation, interoperability, and cross-border cooperation, the 8ra Initiative empowers industries, researchers, and policymakers to shape the next generation of cloud and edge computing. Whether in AI, data spaces, telecommunications, or the industrial metaverse, the 8ra Initiative enables groundbreaking advancements free from vendor lock-in. In March 2025, the Linux Foundation Europe officially announced the launch of the non-profit open source NeoNephos Foundation as part of the Apeiro Reference Architecture Project of SAP. NeoNephos is dedicated to advancing open source projects that align with the strategic objectives of the EU&#39;s IPCEI-Next Generation Cloud Infrastructure and Services (CIS).</em></p><p>🗓 <strong>Date</strong>: November 17th, 2025 at 14:00-16:00 CET.</p><p>👉 Register today <a href="https://www.linkedin.com/events/7392206150483623936/" target="_blank" rel="noreferrer">through here</a>!</p><p>For any questions to this specific event, reach out to <a href="./events@neonephos.org">events@neonephos.org</a>.</p>',10)]))}const m=t(i,[["render",a]]);export{h as __pageData,m as default};
